mapper.select:
SELECT u.id, u.email, u.password_hash, u.role, u.name, u.headline,
       u.avatar_url, u.location, u.status, u.created_at, u.updated_at
FROM `user` u
WHERE u.id != #{userId}
  AND u.status = 'ACTIVE'
  AND u.id NOT IN (
      SELECT CASE WHEN requester_id = #{userId} THEN addressee_id ELSE requester_id END
      FROM connection
      WHERE requester_id = #{userId} OR addressee_id = #{userId}
  )
ORDER BY (
    SELECT COUNT(*)
    FROM user_skill us2
    WHERE us2.user_id = u.id
      AND us2.skill_id IN (
          SELECT skill_id FROM user_skill WHERE user_id = #{userId}
      )
) DESC, u.created_at DESC
LIMIT #{limit}

SELECT id, requester_id, addressee_id, status, created_at, updated_at
FROM connection
WHERE requester_id = #{requesterId}
  AND addressee_id = #{addresseeId}

SELECT id, requester_id, addressee_id, status, created_at, updated_at
FROM connection
WHERE id = #{id}

mapper.update:
UPDATE connection
SET status = #{status}
WHERE id = #{id}
  AND addressee_id = #{addresseeId}

mapper.delete:
DELETE FROM connection
WHERE id = #{id}
  AND (requester_id = #{userId} OR addressee_id = #{userId})

DELETE FROM connection
WHERE requester_id = #{requesterId}
  AND addressee_id = #{addresseeId}
  AND status = 'PENDING'
